def patch_transformers_rmsnorm(model, custom_rmsnorm_fn):
    """Patch all RMSNorm modules in a transformers model."""
    patched = 0
    for name, module in model.named_modules():
        if type(module).__name__ in ('LlamaRMSNorm', 'Qwen2RMSNorm', 'GemmaRMSNorm', 'RMSNorm'):
            eps = getattr(module, 'variance_epsilon', getattr(module, 'eps', 1e-6))
            def make_forward(mod, _eps):
                def forward(hidden_states):
                    return custom_rmsnorm_fn(hidden_states, mod.weight, _eps)
                return forward
            module.forward = make_forward(module, eps)
            patched += 1
    return patched
